<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Branch.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getAutoInstance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
